  3→package e2e
  4→
  5→import (
  6→	"encoding/json"
  7→	"fmt"
  8→	"os"
  9→	"os/exec"
 10→	"path/filepath"
 11→	"testing"
 12→)
 13→
 14→// TestEnv provides an isolated filesystem environment for E2E tests.
 15→type TestEnv struct {
 16→	t       *testing.T
 17→	Dir     string
 18→	HomeDir string
 19→	Runner  *AgentRunner
 20→}
 21→
 22→// NewTestEnv creates a bare test environment with ENTIRE_REPO_ROOT and isolated HOME.
 23→func NewTestEnv(t *testing.T, agentName string) *TestEnv {
 24→	t.Helper()
 25→
 26→	binPath, ok := agentBinaries[agentName]
 27→	if !ok {
 28→		t.Fatalf("agent binary not found: %s (available: %v)", agentName, agentBinaryNames())
 29→	}
 30→
 31→	dir := t.TempDir()
 32→	homeDir := t.TempDir()
 33→
 34→	env := baseEnv(dir, homeDir)
 35→
 36→	return &TestEnv{
 37→		t:       t,
 38→		Dir:     dir,
 39→		HomeDir: homeDir,
 40→		Runner: &AgentRunner{
 41→			BinaryPath: binPath,
 42→			Env:        env,
 43→		},
 44→	}
 45→}
 46→
 47→// NewKiroTestEnv creates a test environment with .kiro/ and .entire/tmp/ directories.
 48→func NewKiroTestEnv(t *testing.T) *TestEnv {
 49→	t.Helper()
 50→	te := NewTestEnv(t, "entire-agent-kiro")
 51→	te.MkdirAll(".kiro")
 52→	te.MkdirAll(".entire/tmp")
 53→	return te
 54→}
 55→
 56→// NewKiroGitEnv creates a Kiro test environment with git init.
 57→func NewKiroGitEnv(t *testing.T) *TestEnv {
 58→	t.Helper()
 59→	te := NewKiroTestEnv(t)
 60→	te.GitInit()
 61→	return te
 62→}
 63→
 64→// WriteFile writes content to a path relative to the test environment root.
 65→func (e *TestEnv) WriteFile(relPath, content string) {
 66→	e.t.Helper()
 67→	abs := filepath.Join(e.Dir, relPath)
 68→	if err := os.MkdirAll(filepath.Dir(abs), 0o750); err != nil {
 69→		e.t.Fatalf("mkdir for %s: %v", relPath, err)
 70→	}
 71→	if err := os.WriteFile(abs, []byte(content), 0o600); err != nil {
 72→		e.t.Fatalf("write %s: %v", relPath, err)
 73→	}
 74→}
 75→
 76→// WriteJSON writes a JSON-encoded value to a path relative to the test root.
 77→func (e *TestEnv) WriteJSON(relPath string, v any) {
 78→	e.t.Helper()
 79→	data, err := json.Marshal(v)
 80→	if err != nil {
 81→		e.t.Fatalf("marshal JSON for %s: %v", relPath, err)
 82→	}
 83→	e.WriteFile(relPath, string(data))
 84→}
 85→
 86→// ReadFile reads a file relative to the test environment root.
 87→func (e *TestEnv) ReadFile(relPath string) string {
 88→	e.t.Helper()
 89→	data, err := os.ReadFile(filepath.Join(e.Dir, relPath))
 90→	if err != nil {
 91→		e.t.Fatalf("read %s: %v", relPath, err)
 92→	}
 93→	return string(data)
 94→}
 95→
 96→// FileExists checks whether a relative path exists in the test environment.
 97→func (e *TestEnv) FileExists(relPath string) bool {
 98→	_, err := os.Stat(filepath.Join(e.Dir, relPath))
 99→	return err == nil
100→}
101→
102→// MkdirAll creates a directory (and parents) relative to the test root.
103→func (e *TestEnv) MkdirAll(relPath string) {
104→	e.t.Helper()
105→	if err := os.MkdirAll(filepath.Join(e.Dir, relPath), 0o750); err != nil {
106→		e.t.Fatalf("mkdir %s: %v", relPath, err)
107→	}
108→}
109→
110→// GitInit initializes a git repo in the test environment root.
111→func (e *TestEnv) GitInit() {
112→	e.t.Helper()
113→	cmd := exec.Command("git", "init")
114→	cmd.Dir = e.Dir
115→	cmd.Env = e.Runner.Env
116→	if out, err := cmd.CombinedOutput(); err != nil {
117→		e.t.Fatalf("git init failed: %v\n%s", err, out)
118→	}
119→}
120→
121→// AbsPath returns the absolute path for a relative path in the test environment.
122→func (e *TestEnv) AbsPath(relPath string) string {
123→	return filepath.Join(e.Dir, relPath)
124→}
125→
126→func baseEnv(repoRoot, homeDir string) []string {
127→	return []string{
128→		fmt.Sprintf("ENTIRE_REPO_ROOT=%s", repoRoot),
129→		fmt.Sprintf("HOME=%s", homeDir),
130→		fmt.Sprintf("PATH=%s", os.Getenv("PATH")),
131→		"LANG=en_US.UTF-8",
132→	}
133→}
134→
135→func agentBinaryNames() []string {
136→	names := make([]string, 0, len(agentBinaries))
137→	for name := range agentBinaries {
138→		names = append(names, name)
139→	}
140→	return names
141→}
