  9→
 10→// HookInput builds stdin payloads for hook-related subcommands.
 11→type HookInput struct {
 12→	HookType   string                 `json:"hook_type,omitempty"`
 13→	SessionID  string                 `json:"session_id,omitempty"`
 14→	SessionRef string                 `json:"session_ref,omitempty"`
 15→	Timestamp  string                 `json:"timestamp,omitempty"`
 16→	UserPrompt string                 `json:"user_prompt,omitempty"`
 17→	ToolName   string                 `json:"tool_name,omitempty"`
 18→	ToolUseID  string                 `json:"tool_use_id,omitempty"`
 19→	ToolInput  json.RawMessage        `json:"tool_input,omitempty"`
 20→	RawData    map[string]interface{} `json:"raw_data,omitempty"`
 21→}
 22→
 23→// JSON returns the JSON-encoded string for use as stdin.
 24→func (h HookInput) JSON(t *testing.T) string {
 25→	t.Helper()
 26→	data, err := json.Marshal(h)
 27→	if err != nil {
 28→		t.Fatalf("marshal HookInput: %v", err)
 29→	}
 30→	return string(data)
 31→}
 32→
 33→// ParseHookInput builds stdin payloads for the parse-hook subcommand.
 34→type ParseHookInput struct {
 35→	HookEventName string          `json:"hook_event_name,omitempty"`
 36→	CWD           string          `json:"cwd,omitempty"`
 37→	Prompt        string          `json:"prompt,omitempty"`
 38→	ToolName      string          `json:"tool_name,omitempty"`
 39→	ToolInput     json.RawMessage `json:"tool_input,omitempty"`
 40→}
 41→
 42→// JSON returns the JSON-encoded string.
 43→func (p ParseHookInput) JSON(t *testing.T) string {
 44→	t.Helper()
 45→	data, err := json.Marshal(p)
 46→	if err != nil {
 47→		t.Fatalf("marshal ParseHookInput: %v", err)
 48→	}
 49→	return string(data)
 50→}
 51→
 52→// KiroTranscript builds Kiro-format transcript files for testing.
 53→type KiroTranscript struct {
 54→	ConversationID string              `json:"conversation_id"`
 55→	History        []kiroHistoryEntry  `json:"history"`
 56→}
 57→
 58→type kiroHistoryEntry struct {
 59→	User      kiroUserMessage `json:"user"`
 60→	Assistant json.RawMessage `json:"assistant"`
 61→}
 62→
 63→type kiroUserMessage struct {
 64→	Content   json.RawMessage `json:"content"`
 65→	Timestamp string          `json:"timestamp,omitempty"`
 66→}
 67→
 68→// NewKiroTranscript creates a new transcript builder.
 69→func NewKiroTranscript(id string) *KiroTranscript {
 70→	return &KiroTranscript{ConversationID: id}
 71→}
 72→
 73→// AddPrompt adds a user prompt entry with no assistant response.
 74→func (kt *KiroTranscript) AddPrompt(prompt string) *KiroTranscript {
 75→	promptContent := map[string]interface{}{
 76→		"Prompt": map[string]string{"prompt": prompt},
 77→	}
 78→	content, _ := json.Marshal(promptContent)
 79→	kt.History = append(kt.History, kiroHistoryEntry{
 80→		User: kiroUserMessage{Content: content},
 81→	})
 82→	return kt
 83→}
 84→
 85→// AddPromptWithFileEdit adds a user prompt paired with an assistant response that contains a file edit tool use.
 86→func (kt *KiroTranscript) AddPromptWithFileEdit(prompt, filePath string) *KiroTranscript {
 87→	promptContent := map[string]interface{}{
 88→		"Prompt": map[string]string{"prompt": prompt},
 89→	}
 90→	userContent, _ := json.Marshal(promptContent)
 91→
 92→	toolUse := map[string]interface{}{
 93→		"ToolUse": map[string]interface{}{
 94→			"message_id": "msg-001",
 95→			"tool_uses": []map[string]interface{}{
 96→				{
 97→					"id":   "tool-001",
 98→					"name": "fs_write",
 99→					"args": map[string]string{"path": filePath},
100→				},
101→			},
102→		},
103→	}
104→	assistantContent, _ := json.Marshal(toolUse)
105→
106→	kt.History = append(kt.History, kiroHistoryEntry{
107→		User:      kiroUserMessage{Content: userContent},
108→		Assistant: assistantContent,
109→	})
110→	return kt
111→}
112→
113→// AddResponse adds a user prompt paired with an assistant text response.
114→func (kt *KiroTranscript) AddResponse(prompt, response string) *KiroTranscript {
115→	promptContent := map[string]interface{}{
116→		"Prompt": map[string]string{"prompt": prompt},
117→	}
118→	userContent, _ := json.Marshal(promptContent)
119→
120→	responseContent := map[string]interface{}{
121→		"Response": map[string]interface{}{
122→			"message_id": "msg-resp",
123→			"content":    response,
124→		},
125→	}
126→	assistantContent, _ := json.Marshal(responseContent)
127→
128→	kt.History = append(kt.History, kiroHistoryEntry{
129→		User:      kiroUserMessage{Content: userContent},
130→		Assistant: assistantContent,
131→	})
132→	return kt
133→}
134→
135→// JSON returns the JSON-encoded transcript string.
136→func (kt *KiroTranscript) JSON(t *testing.T) string {
137→	t.Helper()
138→	data, err := json.Marshal(kt)
139→	if err != nil {
140→		t.Fatalf("marshal KiroTranscript: %v", err)
141→	}
142→	return string(data)
143→}
144→
145→// WriteToFile writes the transcript to a file and returns the absolute path.
146→func (kt *KiroTranscript) WriteToFile(t *testing.T, env *TestEnv, relPath string) string {
147→	t.Helper()
148→	env.WriteFile(relPath, kt.JSON(t))
149→	return env.AbsPath(relPath)
150→}
