132→func TestKiro_ResolveSessionFile(t *testing.T) {
133→	t.Parallel()
134→	env := NewKiroTestEnv(t)
135→
136→	sessionDir := env.AbsPath(".entire/tmp")
137→
138→	var resp struct {
139→		SessionFile string `json:"session_file"`
140→	}
141→	env.Runner.RunJSON(t, &resp, "", "resolve-session-file",
142→		"-session-dir", sessionDir,
143→		"-session-id", "abc-123")
144→
145→	want := sessionDir + "/abc-123.json"
146→	if resp.SessionFile != want {
147→		t.Errorf("session_file = %q, want %q", resp.SessionFile, want)
148→	}
