151→func TestKiro_WriteAndReadSession(t *testing.T) {
152→	t.Parallel()
153→	env := NewKiroTestEnv(t)
154→
155→	sessionRef := env.AbsPath(".entire/tmp/sess-write-test.json")
156→
157→	// Write a session
158→	writeInput := map[string]interface{}{
159→		"session_id":  "sess-write-test",
160→		"agent_name":  "kiro",
161→		"repo_path":   env.Dir,
162→		"session_ref": sessionRef,
163→		"start_time":  "2026-01-01T00:00:00Z",
164→		"native_data": []byte(`{"hello":"world"}`),
165→	}
166→	writeJSON, _ := json.Marshal(writeInput)
167→	env.Runner.MustSucceed(t, string(writeJSON), "write-session")
168→
169→	// Verify the file was written
170→	if !env.FileExists(".entire/tmp/sess-write-test.json") {
